  ('dietitian-moex-03893', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關腹膜透析（CAPD）與血液透析差別的敘述，下列何者錯誤？', '["腹膜透析會流失較多的蛋白質", "使用腹膜透析時應降低熱量攝取，以免體重增加太多", "使用腹膜透析時水分的限制較嚴格", "使用腹膜透析時的透析時間較長"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03894', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何者不是神經性厭食症（Anorexia nervosa）生理和臨床症狀？', '["有胎毛類型毛髮（lanugo）", "低血壓", "肢端發紺", "低胡蘿蔔素血症"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03895', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王先生使用鼻胃管灌食，每日5次，每次250 c.c.，灌食後常發生肺內異物的吸入危險性，下列何者可改 善王先生之上述問題？', '["改以高纖維配方，每日5次，每次250 c.c", "改以限水配方，每日4次，每次350 c.c", "改以自然食物為配方，每日5次灌食，每次250 c.c", "維持原配方，改為連續灌食"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03896', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關巨球性貧血檢測的敘述，下列何者錯誤？', '["同半胱胺酸濃度上升表示維生素B 或葉酸缺乏 1B2", "欲瞭解維生素B 的吸收是否正常，可透過希林試驗（Schilling Test） 1B2", "血清或尿中甲基丙二酸（Methylmalonic acid）濃度上升，表示葉酸缺乏", "紅血球細胞葉酸濃度比血清葉酸濃度，更能反應葉酸儲存量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03897', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何種措施無法預防肝臟移植手術後使用抗排斥藥物糖皮質激素（Glucocorticoids）所引起之副作用？', '["降低鈉攝取量", "降低單醣攝取量", "限制脂肪攝取量", "降低蛋白質攝取量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03898', 'dietitian', 'dietitian-moex-100-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '健康食品之製造、輸入許可證有效期限為5年，期滿仍須繼續製造、輸入者，應於許可證到期前3個月 內申請中央主管機關核准展延之。但每次展延不得超過幾年？', '["3", "5", "7", "10"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "b66576cd714e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03899', 'dietitian', 'dietitian-moex-100-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據行政院衛生署之公告，對健康食品中熱量、營養素及保健功效之相關成分含量標示之單位：規定 「蛋白質」以何種單位表示？', '["公克", "微克", "毫克", "毫微克"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "b66576cd714e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03900', 'dietitian', 'dietitian-moex-100-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '未經核准擅自製造或輸入健康食品者，將受何處罰？', '["處一年以下有期徒刑，得併科新臺幣三十萬元以下罰金", "處二年以下有期徒刑，得併科新臺幣五十萬元以下罰金", "處三年以下有期徒刑，得併科新臺幣一百萬元以下罰金", "處五年以下有期徒刑，得併科新臺幣一百萬元以下罰金"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "b66576cd714e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
